import React, { useCallback, useEffect, useMemo, useState } from 'react';
import {
  Button,
  Input,
  Select,
  detectDateRangePreset,
  SearchTextInput,
  LIN_ERP_LIST_FILTER_LAYOUT,
  LinErpListFilterBar,
  dispatchAppToast,
  LinPageLayout,
  useCatalogTableBusy,
  useErpListSelection,
  useViewMobileLayout,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { useDieuChuyenVtListFilterState } from '../../../hooks/useDieuChuyenVtListFilterState';
import { useDieuChuyenVtPermissions } from '../../../hooks/useDieuChuyenVtPermissions';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { wmsService } from '../../../services/kho/wmsService';
import type { VoucherLineDto, WarehouseTransferDto } from '../../../services/kho/models';
import { VOUCHER_STATUS_OPTIONS } from '../../../utils/constants';
import { LIST_FILTER_SCOPE } from '../../../constants/listFilterScopes';
import { dieuChuyenVtPageLabels } from '../../../constants/dieuChuyenVtPageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { LIST_UI_SCHEMA_KIND } from '../../../types/catalogUiSchema';
import { ListUiSchemaEditorModal } from '../../../components/listUiSchema';
import { WmsSchemaListGrid } from '../../../components/list/WmsSchemaListGrid';
import {
  VoucherRowActionMenu,
  type VoucherRowMenuAction,
} from '../../../components/voucher-list/VoucherRowActionMenu';
import { buildPurchasingListToolbar } from '../../../features/mh/purchasingListToolbar';
import {
  DEFAULT_PAGE_SIZE,
  VoucherListPagination,
  type ListPageSize,
} from '../../../components/list/VoucherListPagination';
import { LineMaterialSearchCell, MaterialLineTableHeaders } from '../../../components/search';
import { InlineVoucherMaterialCreatePanel } from '../../../components/form';
import erp from '../../../styles/erpPage.module.css';
import df from '../../../styles/documentForm.module.css';

const TEST_ID = 'erp-kho-dieu-chuyen-vt';
const PAGE_ID = 'kho-dieu-chuyen-vt';

const emptyLine = (): VoucherLineDto => ({
  materialCode: '',
  materialName: '',
  unitCode: '',
  quantity: 1,
  unitPrice: 0,
  amount: 0,
});

const DieuChuyenVtPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const viewMobile = useViewMobileLayout();
  const { canCreate, canPost, canWrite, canRead } = useDieuChuyenVtPermissions();
  const {
    initialized,
    fromDate,
    toDate,
    datePreset,
    applyDateRange,
    searchDraft,
    setSearchDraft,
    search,
    setSearch,
    status,
    setStatus,
    page,
    setPage,
    resetPage,
  } = useDieuChuyenVtListFilterState(LIST_FILTER_SCOPE.dieuChuyenVt);

  const [showForm, setShowForm] = useState(false);
  const [items, setItems] = useState<WarehouseTransferDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [pageSize, setPageSize] = useState<ListPageSize>(DEFAULT_PAGE_SIZE);
  const [showSchemaEditor, setShowSchemaEditor] = useState(false);
  const [rowMenu, setRowMenu] = useState<{ x: number; y: number; row: WarehouseTransferDto } | null>(null);

  const selection = useErpListSelection({
    rows: items,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
  });
  const [voucherDate, setVoucherDate] = useState(() => new Date().toISOString().slice(0, 10));
  const [fromWarehouseId, setFromWarehouseId] = useState('');
  const [toWarehouseId, setToWarehouseId] = useState('');
  const [lines, setLines] = useState<VoucherLineDto[]>([emptyLine()]);
  const [saving, setSaving] = useState(false);

  const { warehouseOptions } = useVoucherInitData('create-warehouse-transfer');
  const whOpts = [{ value: '', label: '— Kho —' }, ...warehouseOptions];

  const refresh = useCallback(() => {
    setReloadKey(k => k + 1);
    selection.clearActiveRow();
  }, [selection]);
  const handleSearch = useCallback(() => {
    setSearch(searchDraft.trim());
    resetPage();
    selection.clearActiveRow();
  }, [searchDraft, setSearch, resetPage, selection]);
  const { showTableLoading } = useCatalogTableBusy(loading);

  const activeRow = selection.activeRow;

  useEffect(() => {
    if (!initialized) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      wmsService.getWarehouseTransfers({
        status: status || undefined,
        fromDate: fromDate ? `${fromDate}T00:00:00.000Z` : undefined,
        toDate: toDate ? `${toDate}T23:59:59.999Z` : undefined,
        search: search || undefined,
        page,
        pageSize,
      })
        .then(res => {
          if (cancelled) return;
          setItems(res.items);
          setTotalCount(res.totalCount);
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, dieuChuyenVtPageLabels.loadError),
              type: 'error',
            });
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [initialized, status, fromDate, toDate, page, pageSize, search, dispatch, reloadKey]);

  const updateLine = (idx: number, patch: Partial<VoucherLineDto>) => {
    setLines(prev => prev.map((l, i) => (i === idx ? { ...l, ...patch } : l)));
  };

  const handleCreate = async () => {
    if (!fromWarehouseId || !toWarehouseId) {
      dispatchAppToast(dispatch, { message: dieuChuyenVtPageLabels.warehouseWarning, type: 'warning' });
      return;
    }
    if (!lines.some(l => l.materialCode.trim())) {
      dispatchAppToast(dispatch, { message: dieuChuyenVtPageLabels.minLineWarning, type: 'warning' });
      return;
    }
    setSaving(true);
    try {
      await wmsService.createWarehouseTransfer({
        voucherDate: new Date(voucherDate).toISOString(),
        fromWarehouseId,
        toWarehouseId,
        lines: lines.filter(l => l.materialCode.trim()),
      });
      dispatchAppToast(dispatch, { message: dieuChuyenVtPageLabels.createSuccess, type: 'success' });
      setShowForm(false);
      setLines([emptyLine()]);
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, dieuChuyenVtPageLabels.saveError),
        type: 'error',
      });
    } finally {
      setSaving(false);
    }
  };

  const handlePost = useCallback(async (id: string) => {
    try {
      await wmsService.postWarehouseTransfer(id);
      dispatchAppToast(dispatch, { message: dieuChuyenVtPageLabels.postSuccess, type: 'success' });
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, dieuChuyenVtPageLabels.postError),
        type: 'error',
      });
    }
  }, [dispatch, refresh]);

  const canPostActive = activeRow?.status === 'Draft' && canPost;
  const hasRowMenu = canRead || canPost || canWrite;

  const handleRowMenuSelect = useCallback(
    (action: VoucherRowMenuAction) => {
      const row = rowMenu?.row;
      if (!row) return;
      if (action === 'view') {
        selection.selectActiveRow(row);
        setShowForm(false);
      }
    },
    [rowMenu?.row, selection],
  );

  const toolbarProps = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      profile: 'voucher' as const,
      actions: buildPurchasingListToolbar({
        testIdPrefix: TEST_ID,
        onRefresh: refresh,
        onEditConfig: () => setShowSchemaEditor(true),
        canCreate: canCreate && !showForm,
        onCreate: () => setShowForm(true),
        canApprove: canPostActive,
        onApprove: () => activeRow && void handlePost(activeRow.id),
        approveLabel: 'Ghi sổ',
      }),
    }),
    [refresh, canCreate, showForm, canPostActive, activeRow, handlePost],
  );

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        fromDate={fromDate}
        toDate={toDate}
        onDateChange={(from, to) => {
          applyDateRange(from, to, detectDateRangePreset(from, to) || 'custom');
          resetPage();
        }}
        onSearch={handleSearch}
        loading={showTableLoading}
        leading={(
          <>
            <div data-testid={`${TEST_ID}-field-search`}>
              <SearchTextInput
                label="Tìm kiếm"
                value={searchDraft}
                onChange={setSearchDraft}
                onSearch={handleSearch}
                placeholder="Số phiếu, kho nguồn, kho đích…"
                testId={`${TEST_ID}-search-text`}
              />
            </div>
            <div data-testid={`${TEST_ID}-field-status`}>
              <Select
                label="Trạng thái"
                value={status}
                onChange={e => { setStatus(e.target.value); resetPage(); }}
                options={VOUCHER_STATUS_OPTIONS}
                data-testid={`${TEST_ID}-filter-status`}
              />
            </div>
          </>
        )}
      />
    ),
    [
      fromDate,
      toDate,
      searchDraft,
      status,
      applyDateRange,
      resetPage,
      setSearchDraft,
      handleSearch,
      setStatus,
      showTableLoading,
    ],
  );

  const createPanel = showForm && canWrite ? (
    <InlineVoucherMaterialCreatePanel
      testId={`${TEST_ID}-create-form`}
      headerFields={(
        <div className={df.row4}>
          <div className={df.field}>
            <label className={df.label}>Ngày</label>
            <Input type="date" value={voucherDate} onChange={e => setVoucherDate(e.target.value)} size="small" />
          </div>
          <div className={df.field}>
            <label className={df.label}>Kho nguồn</label>
            <Select value={fromWarehouseId} onChange={e => setFromWarehouseId(e.target.value)} options={whOpts} size="small" />
          </div>
          <div className={df.field}>
            <label className={df.label}>Kho đích</label>
            <Select value={toWarehouseId} onChange={e => setToWarehouseId(e.target.value)} options={whOpts} size="small" />
          </div>
        </div>
      )}
      lines={lines}
      setLines={setLines}
      updateLine={updateLine}
      emptyLine={emptyLine}
      onSave={handleCreate}
      onClose={() => setShowForm(false)}
      saving={saving}
    />
  ) : null;

  const listBody = (
    <WmsSchemaListGrid
      catalogKind={LIST_UI_SCHEMA_KIND.warehouseTransfer}
      testIdPrefix={TEST_ID}
      rows={items}
      page={page}
      pageSize={pageSize}
      showTableLoading={showTableLoading}
      viewMobile={viewMobile}
      emptyLabel={dieuChuyenVtPageLabels.empty}
      selection={selection}
      onRowOpenActionMenu={
        hasRowMenu
          ? ({ row, x, y }) => {
              selection.selectActiveRow(row);
              setRowMenu({ x, y, row });
            }
          : undefined
      }
    />
  );

  return (
    <div className={erp.voucherListRoot} data-voucher-list-page data-testid={`${TEST_ID}-list`}>
      <LinPageLayout
        kind="voucher"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: dieuChuyenVtPageLabels.listTitle,
          titleIconClass: 'fas fa-exchange-alt',
          pageId: PAGE_ID,
        }}
        toolbarProps={toolbarProps}
        listTitle={dieuChuyenVtPageLabels.listSubtitle}
        listRowMenuHelp={hasRowMenu}
        filters={listFilters}
        listLayoutVariant="erp-filter-bar"
        listHeaderClassName={LIN_ERP_LIST_FILTER_LAYOUT.header}
        listFiltersClassName={LIN_ERP_LIST_FILTER_LAYOUT.filtersHost}
        showTableLoading={showTableLoading}
        skeletonRows={6}
        footer={(
          <VoucherListPagination
            testIdPrefix={TEST_ID}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={p => { setPage(p); selection.clearActiveRow(); }}
            onPageSizeChange={size => {
              setPageSize(size as ListPageSize);
              setPage(1);
              selection.clearActiveRow();
            }}
          />
        )}
        modals={(
          <>
            <ListUiSchemaEditorModal
              testIdPrefix={TEST_ID}
              catalogKind={LIST_UI_SCHEMA_KIND.warehouseTransfer}
              isOpen={showSchemaEditor}
              onClose={() => setShowSchemaEditor(false)}
              title="Cấu hình hiển thị danh sách"
              onSaved={() => { setReloadKey(k => k + 1); }}
            />
            {hasRowMenu ? (
              <VoucherRowActionMenu
                open={rowMenu != null}
                x={rowMenu?.x ?? 0}
                y={rowMenu?.y ?? 0}
                onClose={() => setRowMenu(null)}
                onSelect={handleRowMenuSelect}
                testIdPrefix={TEST_ID}
                showView={canRead}
                showEdit={false}
                showViewLedger={false}
              />
            ) : null}
          </>
        )}
      >
        {createPanel}
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default DieuChuyenVtPage;
